// Calcula a janela da semana atual (segunda a domingo) no fuso local.
const tipo = $input.first().json.tipo;
const offsetTz = 3 * 3600 * 1000; // ajuste de fuso de exemplo (UTC-3)
const agora = new Date();
const agoraLocal = new Date(agora.getTime() - offsetTz);
const diaSemana = agoraLocal.getUTCDay();
const diasAteSeg = diaSemana === 0 ? 6 : diaSemana - 1;
const segunda = new Date(agoraLocal);
segunda.setUTCDate(segunda.getUTCDate() - diasAteSeg);
segunda.setUTCHours(0, 0, 0, 0);
const domingo = new Date(segunda);
domingo.setUTCDate(domingo.getUTCDate() + 6);
domingo.setUTCHours(23, 59, 59, 0);
const startDateTime = new Date(segunda.getTime() + offsetTz).toISOString();
const endDateTime = new Date(domingo.getTime() + offsetTz).toISOString();
const opts = { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: 'UTC' };
const semanaLabel = segunda.toLocaleDateString('pt-BR', opts) + ' a ' + domingo.toLocaleDateString('pt-BR', opts);
const hojeStr = agoraLocal.toISOString().slice(0, 10);
return [{ json: { tipo, startDateTime, endDateTime, semanaLabel, hojeStr } }];

// Lista ficticia da equipe. Em producao, troque por uma fonte real (planilha, banco, API).
const { tipo, startDateTime, endDateTime, semanaLabel, hojeStr } = $input.first().json;
const equipe = [
  { nome: 'Membro 1', email: 'membro1@exemplo.dev' },
  { nome: 'Membro 2', email: 'membro2@exemplo.dev' },
  { nome: 'Membro 3', email: 'membro3@exemplo.dev' },
  { nome: 'Membro 4', email: 'membro4@exemplo.dev' }
];
return equipe.map(membro => ({ json: { tipo, startDateTime, endDateTime, semanaLabel, hojeStr, membro } }));

// Junta cada resposta da API ao respectivo membro (preserva a ordem dos itens).
const respostas = $input.all();
const membrosDados = $('Montar Lista da Equipe').all();
const base = membrosDados[0].json;
const equipe = respostas.map((item, i) => {
  const membro = membrosDados[i].json.membro;
  const corpo = item.json;
  if (corpo && corpo.error) {
    return { membro, eventos: [], erroAPI: '[' + corpo.error.code + '] ' + corpo.error.message };
  }
  return { membro, eventos: (corpo && corpo.value) || [] };
});
return [{ json: { tipo: base.tipo, semanaLabel: base.semanaLabel, startDateTime: base.startDateTime, endDateTime: base.endDateTime, hojeStr: base.hojeStr, equipe } }];

// Monta um e-mail HTML simples agrupando os eventos por dia, para cada membro.
const { semanaLabel, equipe, hojeStr } = $input.first().json;
const COR = '#2563eb';

function formatarHora(ev) {
  if (ev.isAllDay) return 'Dia inteiro';
  const ini = ((ev.start && ev.start.dateTime) || '').slice(11, 16);
  const fim = ((ev.end && ev.end.dateTime) || '').slice(11, 16);
  return ini && fim ? ini + 'h - ' + fim + 'h' : 'Horario indefinido';
}

let pessoasHtml = '';
for (let idx = 0; idx < equipe.length; idx++) {
  const { membro, eventos, erroAPI } = equipe[idx];
  pessoasHtml += '<h3 style="font-family:Arial;color:' + COR + ';margin:18px 0 8px;">' + membro.nome + ' <small style="color:#999;font-weight:400;">(' + membro.email + ')</small></h3>';
  let conteudo = '';
  if (erroAPI) {
    conteudo = '<p style="color:#c00;font-family:Arial;">Erro ao buscar agenda: ' + erroAPI + '</p>';
  } else if (!eventos || eventos.length === 0) {
    conteudo = '<p style="color:#888;font-style:italic;font-family:Arial;">Sem compromissos na semana.</p>';
  } else {
    const porDia = {};
    for (const ev of eventos) {
      const chave = (((ev.start && ev.start.dateTime) || (ev.start && ev.start.date) || '')).slice(0, 10);
      (porDia[chave] = porDia[chave] || []).push(ev);
    }
    for (const dataStr of Object.keys(porDia).sort()) {
      const dataObj = new Date(dataStr + 'T12:00:00Z');
      const labelDia = dataObj.toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: '2-digit', timeZone: 'UTC' });
      const ehHoje = dataStr === hojeStr;
      conteudo += '<div style="font-weight:700;font-family:Arial;color:' + (ehHoje ? COR : '#555') + ';margin-top:8px;">' + labelDia + (ehHoje ? ' (HOJE)' : '') + '</div>';
      for (const ev of porDia[dataStr]) {
        const local = (ev.location && ev.location.displayName) ? ' [' + ev.location.displayName + ']' : '';
        conteudo += '<div style="font-family:Arial;font-size:14px;padding:4px 0 4px 10px;border-left:2px solid ' + (ehHoje ? COR : '#ddd') + ';"><b style="color:' + COR + ';">' + formatarHora(ev) + '</b> - ' + (ev.subject || '(sem titulo)') + local + '</div>';
      }
    }
  }
  pessoasHtml += '<div style="background:#f7f7f7;border-left:4px solid ' + COR + ';padding:12px;margin-bottom:12px;">' + conteudo + '</div>';
}

const html = '<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"></head><body style="background:#f2f2f2;margin:0;padding:20px;">' +
  '<div style="max-width:600px;margin:0 auto;background:#fff;padding:24px;font-family:Arial;">' +
  '<h2 style="color:' + COR + ';margin:0 0 4px;">Agenda da Equipe</h2>' +
  '<p style="color:#888;font-size:12px;margin:0 0 16px;">Semana ' + semanaLabel + '</p>' +
  pessoasHtml +
  '<hr style="border:none;border-top:1px solid #eee;margin-top:16px;"><p style="color:#aaa;font-size:11px;">Empresa Exemplo - Relatorio automatico (DEMO)</p>' +
  '</div></body></html>';

return [{ json: { html, semanaLabel } }];

// Monta a mensagem com os compromissos somente do dia atual.
const { equipe, hojeStr } = $input.first().json;
const hoje = new Date(hojeStr + 'T12:00:00Z');
const labelHoje = hoje.toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: '2-digit', timeZone: 'UTC' });

let html = '<h3>Agenda da Equipe - ' + labelHoje + '</h3><hr>';
for (const { membro, eventos, erroAPI } of equipe) {
  html += '<p><b>' + membro.nome + '</b></p>';
  if (erroAPI) { html += '<p><i>Erro ao buscar agenda</i></p>'; continue; }
  const eventosHoje = (eventos || []).filter(ev => (((ev.start && ev.start.dateTime) || (ev.start && ev.start.date) || '')).slice(0, 10) === hojeStr);
  if (eventosHoje.length === 0) { html += '<p><i>Sem compromissos hoje</i></p>'; continue; }
  html += '<ul>';
  for (const ev of eventosHoje) {
    if (ev.isAllDay) {
      html += '<li><b>Dia inteiro</b> - ' + (ev.subject || '(sem titulo)') + '</li>';
    } else {
      const ini = ((ev.start && ev.start.dateTime) || '').slice(11, 16);
      const fim = ((ev.end && ev.end.dateTime) || '').slice(11, 16);
      const local = (ev.location && ev.location.displayName) ? ' [' + ev.location.displayName + ']' : '';
      html += '<li><b>' + ini + ' - ' + fim + '</b> - ' + (ev.subject || '(sem titulo)') + local + '</li>';
    }
  }
  html += '</ul>';
}
html += '<hr><p><i>Empresa Exemplo - Automacao (DEMO)</i></p>';
return [{ json: { mensagemHtml: html, hojeStr } }];

// Guarda um retrato da agenda da semana para comparar nos dias seguintes.
const dados = $('Agregar Equipe').first().json;
const staticData = $getWorkflowStaticData('global');
staticData.snapshot = {
  timestamp: new Date().toISOString(),
  semanaLabel: dados.semanaLabel,
  equipe: dados.equipe.map(p => ({
    email: p.membro.email,
    nome: p.membro.nome,
    eventos: (p.eventos || []).map(ev => ({ id: ev.id, subject: ev.subject, start: ev.start, end: ev.end, isAllDay: ev.isAllDay }))
  }))
};
return [{ json: { sucesso: true, snapshotTimestamp: staticData.snapshot.timestamp } }];

// Compara a agenda atual com o snapshot da semana e detecta NOVO / ALTERADO / CANCELADO.
const { equipe: equipeAtual, semanaLabel, hojeStr } = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const snapshot = staticData.snapshot;
if (!snapshot) {
  return [{ json: { temAlteracoes: false, alteracoes: [], semanaLabel, equipeAtual, hojeStr, aviso: 'Nenhum snapshot encontrado. Rode o relatorio semanal primeiro.' } }];
}
const alteracoes = [];
for (const atual of equipeAtual) {
  const membro = atual.membro;
  const eventosAtuais = atual.eventos || [];
  const pessoaSnap = snapshot.equipe.find(p => p.email === membro.email);
  const eventosSnap = pessoaSnap ? pessoaSnap.eventos : [];
  for (const ev of eventosAtuais) {
    const noSnap = eventosSnap.find(s => s.id === ev.id);
    if (!noSnap) {
      alteracoes.push({ tipo: 'NOVO', membro: membro.nome, evento: ev });
    } else {
      const horaMudou = (noSnap.start && noSnap.start.dateTime) !== (ev.start && ev.start.dateTime) || (noSnap.end && noSnap.end.dateTime) !== (ev.end && ev.end.dateTime);
      const tituloMudou = noSnap.subject !== ev.subject;
      if (horaMudou || tituloMudou) alteracoes.push({ tipo: 'ALTERADO', membro: membro.nome, eventoAnterior: noSnap, evento: ev });
    }
  }
  for (const evSnap of eventosSnap) {
    if (!eventosAtuais.find(e => e.id === evSnap.id)) {
      alteracoes.push({ tipo: 'CANCELADO', membro: membro.nome, evento: evSnap });
    }
  }
}
return [{ json: { temAlteracoes: alteracoes.length > 0, alteracoes, semanaLabel, equipeAtual, hojeStr } }];

// Monta a mensagem de alerta listando o que mudou na agenda.
const { alteracoes, semanaLabel } = $input.first().json;
const novos = alteracoes.filter(a => a.tipo === 'NOVO');
const alterados = alteracoes.filter(a => a.tipo === 'ALTERADO');
const cancelados = alteracoes.filter(a => a.tipo === 'CANCELADO');

function horaEv(ev) {
  if (!ev) return '';
  if (ev.isAllDay) return 'dia inteiro';
  const ini = ((ev.start && ev.start.dateTime) || '').slice(11, 16);
  const fim = ((ev.end && ev.end.dateTime) || '').slice(11, 16);
  return ini && fim ? ini + ' - ' + fim : '';
}
function dataEv(ev) {
  if (!ev) return '';
  const dtStr = (ev.start && ev.start.dateTime) ? ev.start.dateTime : ((ev.start && ev.start.date) ? ev.start.date + 'T12:00:00Z' : '');
  return dtStr ? new Date(dtStr).toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit', timeZone: 'UTC' }) : '';
}

let html = '<h3>Alteracoes na Agenda - Semana ' + semanaLabel + '</h3><hr>';
if (novos.length) {
  html += '<p><b>Novos compromissos:</b></p><ul>';
  for (const a of novos) html += '<li><b>' + a.membro + '</b> - ' + dataEv(a.evento) + ', ' + horaEv(a.evento) + ': ' + (a.evento.subject || '(sem titulo)') + '</li>';
  html += '</ul>';
}
if (alterados.length) {
  html += '<p><b>Compromissos alterados:</b></p><ul>';
  for (const a of alterados) {
    const titulo = (a.evento && a.evento.subject) || (a.eventoAnterior && a.eventoAnterior.subject) || '(sem titulo)';
    html += '<li><b>' + a.membro + '</b> - <b>' + titulo + '</b>: ' + horaEv(a.eventoAnterior) + ' -> ' + horaEv(a.evento) + '</li>';
  }
  html += '</ul>';
}
if (cancelados.length) {
  html += '<p><b>Compromissos cancelados:</b></p><ul>';
  for (const a of cancelados) html += '<li><b>' + a.membro + '</b> - ' + dataEv(a.evento) + ', ' + horaEv(a.evento) + ': ' + (a.evento.subject || '(sem titulo)') + '</li>';
  html += '</ul>';
}
html += '<hr><p><i>Empresa Exemplo - Automacao (DEMO)</i></p>';
return [{ json: { mensagemHtml: html, totalAlteracoes: alteracoes.length } }];

// Atualiza o snapshot apos enviar os alertas, para nao repetir o mesmo aviso amanha.
const { equipeAtual, semanaLabel } = $('Comparar com Snapshot').first().json;
const staticData = $getWorkflowStaticData('global');
staticData.snapshot = {
  timestamp: new Date().toISOString(),
  semanaLabel,
  equipe: equipeAtual.map(p => ({
    email: p.membro.email,
    nome: p.membro.nome,
    eventos: (p.eventos || []).map(ev => ({ id: ev.id, subject: ev.subject, start: ev.start, end: ev.end, isAllDay: ev.isAllDay }))
  }))
};
return [{ json: { sucesso: true, snapshotAtualizado: staticData.snapshot.timestamp } }];
